import React, { useState, useRef, useEffect } from 'react';

const Keyboard_mouse = () => {
  const [startTouch, setStartTouch] = useState(null);  // Punctul de început al atingerii
  const [isClick, setIsClick] = useState(true);  // Stare pentru a detecta dacă e un click simplu sau mișcare
  const sensitivity = 2;  // Factorul de sensibilitate pentru mișcarea cursorului
  const movementBuffer = useRef({ x: 0, y: 0 });  // Buffer pentru acumularea mișcărilor
  const requestRef = useRef();  // Referință pentru requestAnimationFrame

  // Debounce function to limit how often we send data to the server
  const debounce = (func, delay) => {
    let timer;
    return (...args) => {
      if (timer) clearTimeout(timer);
      timer = setTimeout(() => func(...args), delay);
    };
  };

  const sendMouseMove = (deltaX, deltaY) => {
    // Trimite coordonatele relative către server pentru a muta cursorul
    fetch('/shortcuts/keyboard_mouse/move_mouse/', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-CSRFToken': '{{ csrf_token }}',  // Asigură-te că tokenul CSRF este adăugat
      },
      body: JSON.stringify({ action: 'move', x: deltaX, y: deltaY })
    }).catch(error => console.error('Error:', error));
  };

  // Funcția care sincronizează cererile de mișcare cu requestAnimationFrame
  const moveWithAnimationFrame = () => {
    const { x, y } = movementBuffer.current;
    if (x !== 0 || y !== 0) {
      sendMouseMove(x, y);
      movementBuffer.current = { x: 0, y: 0 };  // Resetăm bufferul după trimitere
    }
    requestRef.current = requestAnimationFrame(moveWithAnimationFrame);  // Reapelăm pentru următoarea mișcare
  };

  useEffect(() => {
    // Pornim requestAnimationFrame pentru sincronizarea mișcării
    requestRef.current = requestAnimationFrame(moveWithAnimationFrame);
    return () => cancelAnimationFrame(requestRef.current);  // Curățăm când componenta este demontată
  }, []);

  const handleTouchStart = (event) => {
    const touch = event.touches[0];
    // Salvăm poziția inițială unde degetul atinge touchpad-ul
    setStartTouch({ x: touch.clientX, y: touch.clientY });
    setIsClick(true);  // La începutul atingerii, presupunem că e un click
  };

  const handleTouchMove = (event) => {
    const touch = event.touches[0];
    
    if (startTouch) {
      // Calculăm diferența de mișcare relativă față de poziția inițială și aplicăm factorul de sensibilitate
      const deltaX = (touch.clientX - startTouch.x) * sensitivity;
      const deltaY = (touch.clientY - startTouch.y) * sensitivity;

      // Dacă utilizatorul mișcă degetul, nu mai e un click
      if (Math.abs(deltaX) > 5 || Math.abs(deltaY) > 5) {
        setIsClick(false);  // Dacă delta este semnificativă, e o mișcare, nu un click
      }

      // Acumulăm mișcarea în buffer pentru a trimite cu requestAnimationFrame
      movementBuffer.current = {
        x: movementBuffer.current.x + deltaX,
        y: movementBuffer.current.y + deltaY,
      };

      // Actualizăm punctul de start pentru a continua mișcarea relativă
      setStartTouch({ x: touch.clientX, y: touch.clientY });
    }
  };

  const handleTouchEnd = () => {
    if (isClick) {
      // Dacă nu a fost detectată mișcare semnificativă, trimitem un click stânga simplu
      handleClick('left');
    }
    // Resetăm punctul de start când utilizatorul ridică degetul
    setStartTouch(null);
  };

  const handleClick = (button = 'left', double = false) => {
    // Trimite o cerere POST pentru a face click (stânga, dreapta sau dublu click)
    fetch('/shortcuts/keyboard_mouse/move_mouse/', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-CSRFToken': '{{ csrf_token }}',  // Asigură-te că tokenul CSRF este adăugat
      },
      body: JSON.stringify({ action: 'click', button: button, double: double })
    }).catch(error => console.error('Error:', error));
  };

  const handleRightClick = (event) => {
    event.preventDefault(); // Previne comportamentul default pentru click dreapta
    handleClick('right');
  };

  const handleDoubleClick = () => {
    handleClick('left', true); // Dublu click pe click stânga
  };

  return (
    <div
      className="touchpad-container"
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
      onContextMenu={handleRightClick}  // Captură pentru click dreapta
      onDoubleClick={handleDoubleClick}  // Captură pentru dublu click
      style={{ 
        width: '50vw', 
        height: '50vh',   // Ocupă jumătate din înălțimea vizibilă a ecranului
        backgroundColor: 'lightgray',
        position: 'absolute',
        top: '0',
        left: '0'
      }}
    >
      <h2>Touchpad Controller</h2>
      <p>Use the touchpad to move the mouse and tap to click.</p>
      <p>Right-click by long-pressing or double-tap for double-click.</p>
    </div>
  );
};

export default Keyboard_mouse;
